//Firebase...
import { auth, provider } from "../config/firebase";
import {
  createUserWithEmailAndPassword,
  getRedirectResult,
  signInWithEmailAndPassword,
  signInWithRedirect,
  signInWithPopup,
} from "firebase/auth";

//React...
import { useEffect, useState } from "react";

//React-router...
import { useNavigate } from "react-router-dom";

//React-icons...
import { FcGoogle } from "react-icons/fc";
import MobileNav from "./Mobile-nav";

//Styles...
import "../styles/Login.scss";

export default function Login() {
  const navigate = useNavigate();
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [authMode, setAuthMode] = useState("login");
  const [isSigningIn, setIsSigningIn] = useState(false);
  const [errorMessage, setErrorMessage] = useState("");

  const mapAuthError = (error) => {
    const code = error?.code || "";

    if (code === "auth/popup-closed-by-user") {
      return "Google popup was closed. We can retry or use redirect sign-in.";
    }

    if (code === "auth/popup-blocked") {
      return "Popup was blocked by browser. Please allow popups or continue with redirect.";
    }

    if (code === "auth/unauthorized-domain") {
      return "This domain is not authorized in Firebase Auth. Add localhost in Firebase Console > Authentication > Settings > Authorized domains.";
    }

    if (code === "auth/network-request-failed") {
      return "Network issue during sign-in. Check your connection and try again.";
    }

    if (code === "auth/invalid-credential") {
      return "Invalid credentials. Please check your email/password.";
    }

    if (code === "auth/user-not-found") {
      return "No account found for this email.";
    }

    if (code === "auth/wrong-password") {
      return "Wrong password. Please try again.";
    }

    if (code === "auth/email-already-in-use") {
      return "This email is already in use. Try signing in instead.";
    }

    return error?.message || "Authentication failed. Please try again.";
  };

  useEffect(() => {
    let active = true;

    const checkRedirectResult = async () => {
      try {
        await getRedirectResult(auth);
        if (active && auth.currentUser) {
          navigate("/");
        }
      } catch (error) {
        if (active) {
          setErrorMessage(mapAuthError(error));
        }
      }
    };

    checkRedirectResult();

    return () => {
      active = false;
    };
  }, [navigate]);

  const handleEmailPasswordAuth = async (e) => {
    e.preventDefault();
    setErrorMessage("");
    setIsSigningIn(true);

    try {
      if (!email || !password) {
        throw new Error("Enter both email and password.");
      }

      if (password.length < 6) {
        throw new Error("Password must be at least 6 characters.");
      }

      if (authMode === "create") {
        await createUserWithEmailAndPassword(auth, email, password);
      } else {
        await signInWithEmailAndPassword(auth, email, password);
      }

      navigate("/");
    } catch (error) {
      setErrorMessage(mapAuthError(error));
    } finally {
      setIsSigningIn(false);
    }
  };

  const signUpWithGoogle = async (e) => {
    e.preventDefault();
    setErrorMessage("");
    setIsSigningIn(true);

    try {
      provider.setCustomParameters({ prompt: "select_account" });
      await signInWithPopup(auth, provider);
      navigate("/");
    } catch (error) {
      const popupFallbackCodes = [
        "auth/popup-blocked",
        "auth/popup-closed-by-user",
        "auth/cancelled-popup-request",
      ];

      if (popupFallbackCodes.includes(error?.code)) {
        try {
          await signInWithRedirect(auth, provider);
          return;
        } catch (redirectError) {
          setErrorMessage(mapAuthError(redirectError));
        }
      } else {
        setErrorMessage(mapAuthError(error));
      }
    } finally {
      setIsSigningIn(false);
    }
  };

  return (
    <section className="login-page">
      <MobileNav />
      <article>
        <h1>Hey There</h1>
        <p>Sign in with email/password or continue with Google.</p>

        <div className="auth-mode-toggle" role="tablist" aria-label="Authentication mode">
          <button
            type="button"
            className={`mode-btn ${authMode === "login" ? "active" : ""}`}
            onClick={() => setAuthMode("login")}
          >
            Sign In
          </button>
          <button
            type="button"
            className={`mode-btn ${authMode === "create" ? "active" : ""}`}
            onClick={() => setAuthMode("create")}
          >
            Create Account
          </button>
        </div>

        <form className="email-auth-form" onSubmit={handleEmailPasswordAuth}>
          <input
            type="email"
            placeholder="Email"
            autoComplete="email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
          />
          <input
            type="password"
            placeholder="Password"
            autoComplete={
              authMode === "create" ? "new-password" : "current-password"
            }
            value={password}
            onChange={(e) => setPassword(e.target.value)}
          />
          <button type="submit" className="email-auth-btn" disabled={isSigningIn}>
            {isSigningIn
              ? "Please wait..."
              : authMode === "create"
                ? "Create Account"
                : "Sign In with Email"}
          </button>
        </form>

        <span className="auth-divider">or</span>

        <button
          className="google-auth-btn"
          onClick={signUpWithGoogle}
          disabled={isSigningIn}
        >
          <FcGoogle />
          {isSigningIn ? "Opening Google..." : "Sign in with Google"}
        </button>
        {errorMessage && <p className="login-error">{errorMessage}</p>}
      </article>
    </section>
  );
}
